// frontend/src/components/Dashboard/StatsCards.js
import React from 'react';
import {
  Grid,
  Card,
  CardContent,
  Typography,
  Box,
  Skeleton,
  useTheme
} from '@mui/material';
import {
  TrendingUp,
  TrendingDown,
  AccountBalance,
  ShowChart,
  Timeline,
  Percent
} from '@mui/icons-material';

const StatsCards = ({ stats, loading }) => {
  const theme = useTheme();

  const formatCurrency = (value) => {
    if (value === null || value === undefined) return 'R$ 0,00';
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL'
    }).format(value);
  };

  const formatPercentage = (value) => {
    if (value === null || value === undefined) return '0%';
    return `${value >= 0 ? '+' : ''}${value.toFixed(2)}%`;
  };

  const formatNumber = (value) => {
    if (value === null || value === undefined) return '0';
    return new Intl.NumberFormat('pt-BR').format(value);
  };

  const getColorByValue = (value) => {
    if (value > 0) return theme.palette.success.main;
    if (value < 0) return theme.palette.error.main;
    return theme.palette.text.secondary;
  };

  const statsConfig = [
    {
      title: 'PnL Total',
      value: stats?.total_pnl,
      format: formatCurrency,
      icon: AccountBalance,
      color: getColorByValue(stats?.total_pnl || 0),
      description: 'Lucro/Prejuízo acumulado'
    },
    {
      title: 'ROE Médio',
      value: stats?.average_roe,
      format: formatPercentage,
      icon: Percent,
      color: getColorByValue(stats?.average_roe || 0),
      description: 'Retorno sobre investimento médio'
    },
    {
      title: 'Total de Trades',
      value: stats?.total_trades,
      format: formatNumber,
      icon: ShowChart,
      color: theme.palette.primary.main,
      description: 'Número total de operações'
    },
    {
      title: 'Trades Lucrativos',
      value: stats?.winning_trades,
      format: formatNumber,
      icon: TrendingUp,
      color: theme.palette.success.main,
      description: 'Operações com lucro'
    },
    {
      title: 'Trades Perdedores',
      value: stats?.losing_trades,
      format: formatNumber,
      icon: TrendingDown,
      color: theme.palette.error.main,
      description: 'Operações com prejuízo'
    },
    {
      title: 'Taxa de Acerto',
      value: stats?.win_rate,
      format: formatPercentage,
      icon: Timeline,
      color: getColorByValue(stats?.win_rate || 0),
      description: 'Percentual de trades lucrativos'
    }
  ];

  if (loading) {
    return (
      <Grid container spacing={3}>
        {Array.from({ length: 6 }).map((_, index) => (
          <Grid item xs={12} sm={6} md={4} lg={2} key={index}>
            <Card sx={{ height: '100%' }}>
              <CardContent>
                <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                  <Skeleton variant="circular" width={40} height={40} sx={{ mr: 2 }} />
                  <Box sx={{ flexGrow: 1 }}>
                    <Skeleton variant="text" width="60%" />
                    <Skeleton variant="text" width="40%" />
                  </Box>
                </Box>
                <Skeleton variant="text" width="80%" height={32} />
                <Skeleton variant="text" width="60%" />
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>
    );
  }

  return (
    <Grid container spacing={3}>
      {statsConfig.map((stat, index) => {
        const IconComponent = stat.icon;

        return (
          <Grid item xs={12} sm={6} md={4} lg={2} key={index}>
            <Card
              sx={{
                height: '100%',
                transition: 'all 0.3s ease',
                '&:hover': {
                  transform: 'translateY(-4px)',
                  boxShadow: theme.shadows[8]
                }
              }}
            >
              <CardContent>
                <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                  <Box
                    sx={{
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      width: 40,
                      height: 40,
                      borderRadius: '50%',
                      bgcolor: `${stat.color}20`,
                      mr: 2
                    }}
                  >
                    <IconComponent sx={{ color: stat.color, fontSize: 20 }} />
                  </Box>
                  <Box sx={{ flexGrow: 1 }}>
                    <Typography
                      variant="caption"
                      color="text.secondary"
                      sx={{ fontWeight: 500 }}
                    >
                      {stat.title}
                    </Typography>
                  </Box>
                </Box>

                <Typography
                  variant="h5"
                  sx={{
                    fontWeight: 'bold',
                    color: stat.color,
                    mb: 1,
                    fontSize: { xs: '1.25rem', sm: '1.5rem' }
                  }}
                >
                  {stat.format(stat.value)}
                </Typography>

                <Typography
                  variant="caption"
                  color="text.secondary"
                  sx={{
                    display: 'block',
                    lineHeight: 1.2
                  }}
                >
                  {stat.description}
                </Typography>
              </CardContent>
            </Card>
          </Grid>
        );
      })}
    </Grid>
  );
};

export default StatsCards;
